import React, { useState } from 'react';

export default function AudioExtractor() {
  const [url, setUrl] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(false);

  // Fix 1: Add the explicit type to the event parameter 'e'
  const handleDownload = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!url) return;

    setLoading(true);

    try {
      const response = await fetch('http://localhost:5000/extract', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url }),
      });

      if (!response.ok) throw new Error('Network response failed');

      const blob = await response.blob();
      const downloadUrl = window.URL.createObjectURL(blob);

      const link = document.createElement('a');
      link.href = downloadUrl;
      link.setAttribute('download', 'extracted-audio.mp3'); 

      document.body.appendChild(link);
      link.click();

      // Fix 2: Use modern .remove() directly on the element instead of .parentNode
      link.remove();

      window.URL.revokeObjectURL(downloadUrl);
    } catch (error) {
      console.error("Error downloading file:", error);
      alert("Failed to extract audio.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: '2rem' }}>
      <form onSubmit={handleDownload}>
        <input 
          type="text" 
          value={url} 
          onChange={(e: React.ChangeEvent<HTMLInputElement>) => setUrl(e.target.value)} 
          placeholder="Paste YouTube Link Here..." 
          disabled={loading}
          style={{ width: '300px', marginRight: '10px' }}
        />
        <button type="submit" disabled={loading}>
          {loading ? 'Extracting...' : 'Get Audio'}
        </button>
      </form>
    </div>
  );
}
